def get_smallest_string(s: str) -> str:
    n = len(s)
    s_list = list(s)

    # Find the first position where we can start improving
    start = 0
    while start < n and s_list[start] == 'a':
        start += 1

    if start == n:
        # If all characters are 'a', we must change something
        # Changing the last character to 'z' gives the smallest result
        s_list[-1] = 'z'
        return ''.join(s_list)

    # Start the operation from the first non-'a' character
    end = start
    while end < n and s_list[end] != 'a':
        s_list[end] = chr(ord(s_list[end]) - 1)
        end += 1

    return ''.join(s_list)
