def maxElementSum(nums):
    def square_free(num):
        # Remove all perfect square factors
        result = 1
        # Handle factor 2
        count = 0
        while num % 2 == 0:
            num //= 2
            count += 1
        if count % 2 == 1:
            result *= 2

        # Handle odd factors
        factor = 3
        while factor * factor <= num:
            count = 0
            while num % factor == 0:
                num //= factor
                count += 1
            if count % 2 == 1:
                result *= factor
            factor += 2

        # If remaining num is a prime > 2
        if num > 1:
            result *= num

        return result

    # Group numbers by their square-free part
    groups = {}
    for num in nums:
        sf = square_free(num)
        if sf not in groups:
            groups[sf] = 0
        groups[sf] += num

    # Find the maximum sum
    max_sum = 0
    for sf, total_sum in groups.items():
        if total_sum > max_sum:
            max_sum = total_sum

    return max_sum
```

