from typing import List
import math

def minimumCost(source: str, target: str, original: List[str], changed: List[str], cost: List[int]) -> int:
    # Initialize distance matrix for 26 lowercase letters
    INF = float('inf')
    dist = [[INF] * 26 for _ in range(26)]

    # Distance from a character to itself is 0
    for i in range(26):
        dist[i][i] = 0

    # Fill direct conversions from original to changed
    for orig, chg, cst in zip(original, changed, cost):
        u = ord(orig) - ord('a')
        v = ord(chg) - ord('a')
        dist[u][v] = min(dist[u][v], cst)

    # Floyd-Warshall to find minimum cost between any two characters
    for k in range(26):
        for i in range(26):
            for j in range(26):
                if dist[i][k] != INF and dist[k][j] != INF:
                    dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])

    total_cost = 0
    for s_char, t_char in zip(source, target):
        u = ord(s_char) - ord('a')
        v = ord(t_char) - ord('a')
        if dist[u][v] == INF:
            return -1
        total_cost += dist[u][v]

    return total_cost
