```python
def countSpecialPermutations(nums):
    MOD = 10**9 + 7
    n = len(nums)

    # Precompute divisibility matrix
    divisible = [[False] * n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            if i != j and (nums[i] % nums[j] == 0 or nums[j] % nums[i] == 0):
                divisible[i][j] = True

    # dp[mask][last] = number of ways to form a permutation ending with nums[last]
    dp = [[0] * n for _ in range(1 << n)]

    # Base case: start with any single element
    for i in range(n):
        dp[1 << i][i] = 1

    # Fill DP table
    for mask in range(1 << n):
        for last in range(n):
            if not (mask & (1 << last)):
                continue
            for next_idx in range(n):
                if mask & (1 << next_idx):
                    continue
                if divisible[last][next_idx]:
                    dp[mask | (1 << next_idx)][next_idx] = (dp[mask | (1 << next_idx)][next_idx] + dp[mask][last]) % MOD

    # Sum all ways that use all elements
    full_mask = (1 << n) - 1
    result = sum(dp[full_mask][i] for i in range(n)) % MOD
    return result
```

