def solve():
    input = sys.stdin.readline
    H, W = map(int, input().split())
    grid = [list(input().strip()) for _ in range(H)]

    # If a cell is adjacent to a magnet, it's blocked (can't move from it)
    blocked = [[False] * W for _ in range(H)]

    # Directions: up, down, left, right
    dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    for i in range(H):
        for j in range(W):
            if grid[i][j] == '#':
                for di, dj in dirs:
                    ni, nj = i + di, j + dj
                    if 0 <= ni < H and 0 <= nj < W:
                        blocked[ni][nj] = True

    visited = [[False] * W for _ in range(H)]
    answer = 0

    for i in range(H):
        for j in range(W):
            if grid[i][j] == '.' and not visited[i][j] and not blocked[i][j]:
                # BFS to find all reachable cells in this component
                stack = [(i, j)]
                visited[i][j] = True
                cells = [(i, j)]
                while stack:
                    x, y = stack.pop()
                    for dx, dy in dirs:
                        nx, ny = x + dx, y + dy
                        if 0 <= nx < H and 0 <= ny < W and not visited[nx][ny] and grid[nx][ny] == '.' and not blocked[nx][ny]:
                            visited[nx][ny] = True
                            stack.append((nx, ny))
                            cells.append((nx, ny))

                # For each cell in this component, degree = component size
                size = len(cells)
                answer = max(answer, size)

    # Also consider blocked cells that are not magnets
    for i in range(H):
        for j in range(W):
            if grid[i][j] == '.' and blocked[i][j]:
                answer = max(answer, 1)

    print(answer)

