    def flip_horizontal(grid):
        # Flip over horizontal axis (mirror top-bottom)
        return [grid[3-i][:] for i in range(4)]

    # Since flipping is not allowed, we only consider rotations (0, 90, 180, 270)
    def get_all_orientations(grid):
        orientations = []
        current = grid
        for _ in range(4):
            orientations.append([row[:] for row in current])
            current = rotate90(current)
        return orientations

