def numberOfBeautifulIntegers(low: int, high: int, k: int) -> int:
    def count_up_to(n: int) -> int:
        s = list(map(int, str(n)))
        length = len(s)

        from functools import lru_cache

        @lru_cache(None)
        def dp(pos, tight, diff, mod):
            if pos == length:
                return 1 if diff == 0 and mod == 0 else 0
            limit = s[pos] if tight else 9
            total = 0
            for d in range(limit + 1):
                new_tight = tight and (d == limit)
                new_diff = diff + (1 if d % 2 == 1 else -1)
                new_mod = (mod * 10 + d) % k
                total += dp(pos + 1, new_tight, new_diff, new_mod)
            return total

        return dp(0, True, 0, 0)

    return count_up_to(high) - count_up_to(low - 1)
