def minChanges(s: str, k: int) -> int:
    n = len(s)

    # cost[i][j] = minimum changes to turn substring s[i:j+1] into a semi-palindrome
    cost = [[float('inf')] * n for _ in range(n)]

    for i in range(n):
        for j in range(i, n):
            length = j - i + 1
            best = float('inf')
            # Try all divisors d such that 1 <= d < length and length % d == 0
            for d in range(1, length):
                if length % d != 0:
                    continue
                changes = 0
                # For each remainder mod d, check palindrome condition
                for rem in range(d):
                    chars = []
                    pos = i + rem
                    while pos <= j:
                        chars.append(s[pos])
                        pos += d
                    # minimum changes to make this sequence a palindrome
                    l, r = 0, len(chars) - 1
                    while l < r:
                        if chars[l] != chars[r]:
                            changes += 1
                        l += 1
                        r -= 1
                best = min(best, changes)
            cost[i][j] = best

    # dp[p][c] = minimum changes for first p characters into c substrings
    dp = [[float('inf')] * (k + 1) for _ in range(n + 1)]
    dp[0][0] = 0

    for end in range(1, n + 1):
        for c in range(1, k + 1):
            for start in range(c - 1, end):
                if dp[start][c - 1] != float('inf'):
                    dp[end][c] = min(dp[end][c], dp[start][c - 1] + cost[start][end - 1])

    return dp[n][k]
```

