import sys

def solve():
    input_data = sys.stdin.read().split()
    N = int(input_data[0])
    T_prime = input_data[1]
    strings = input_data[2:]

    results = []

    for idx, S in enumerate(strings, 1):
        # Condition 1: T' equals S
        if T_prime == S:
            results.append(idx)
            continue

        len_T = len(T_prime)
        len_S = len(S)

        # Condition 2: T' is S with one character inserted
        if len_T == len_S + 1:
            # Check if deleting one char from T' gives S
            i = j = 0
            while i < len_T and j < len_S and T_prime[i] == S[j]:
                i += 1
                j += 1
            # Skip one character in T'
            if i < len_T:
                i += 1
            # Check remaining
            while i < len_T and j < len_S:
                if T_prime[i] != S[j]:
                    break
                i += 1
                j += 1
            if i == len_T and j == len_S:
                results.append(idx)
                continue

        # Condition 3: T' is S with one character deleted
        if len_T == len_S - 1:
            # Check if inserting one char into T' gives S
            i = j = 0
            while i < len_T and j < len_S and T_prime[i] == S[j]:
                i += 1
                j += 1
            # Skip one character in S
            if j < len_S:
                j += 1
            # Check remaining
            while i < len_T and j < len_S:
                if T_prime[i] != S[j]:
                    break
                i += 1
                j += 1
            if i == len_T and j == len_S:
                results.append(idx)
                continue

        # Condition 4: T' is S with one character changed
        if len_T == len_S:
            diff_count = 0
            for c1, c2 in zip(T_prime, S):
                if c1 != c2:
                    diff_count += 1
                    if diff_count > 1:
                        break
            if diff_count == 1:
                results.append(idx)
                continue

    # Output
    print(len(results))
    if results:
        print(" ".join(map(str, results)))

