    is_prime = [True] * (n + 1)
    is_prime[0] = is_prime[1] = False

    for i in range(2, int(n**0.5) + 1):
        if is_prime[i]:
            for j in range(i * i, n + 1, i):
                is_prime[j] = False

    # Step 2: Find all valid pairs
    result = []
    for x in range(2, n // 2 + 1):
        y = n - x
        if is_prime[x] and is_prime[y] and x <= y:
            result.append([x, y])

    return result
