def maximize_gold(n: int, offers: list[list[int]]) -> int:
    # Group offers by their end index
    offers_by_end = [[] for _ in range(n)]
    for start, end, gold in offers:
        offers_by_end[end].append((start, gold))

    # dp[i] = maximum gold we can get considering houses 0..i
    dp = [0] * n

    for i in range(n):
        # Option 1: do not sell house i
        if i > 0:
            dp[i] = dp[i - 1]

        # Option 2: consider all offers that end at house i
        for start, gold in offers_by_end[i]:
            # Gold from this offer + best we can do before this offer starts
            if start > 0:
                total_gold = gold + dp[start - 1]
            else:
                total_gold = gold
            dp[i] = max(dp[i], total_gold)

    return dp[n - 1]
