                return current_sum == target
            for end in range(start + 1, len(num_str) + 1):
                part = int(num_str[start:end])
                if current_sum + part > target:
                    break  # early break because numbers only increase
                if backtrack(end, current_sum + part):
                    return True
            return False

        return backtrack(0, 0)

