We can solve this by trying all possible ways to place tiles on the grid using backtracking.  
Since the grid is small (max 10×10) and N ≤ 7, brute force with backtracking is feasible.  

Here’s the Python implementation:  

```python
import sys

def solve():
    input_data = sys.stdin.read().strip().split()
    N, H, W = map(int, input_data[:3])
    tiles = []
    idx = 3
    for _ in range(N):
        a, b = int(input_data[idx]), int(input_data[idx+1])
        idx += 2
        tiles.append((a, b))

    grid = [[0]*W for _ in range(H)]

    # Try to place a tile of size (h, w) at (r, c)
    def can_place(grid, r, c, h, w):
        if r + h > H or c + w > W:
            return False
        for i in range(h):
            for j in range(w):
                if grid[r+i][c+j] != 0:
                    return False
        return True

    def place(grid, r, c, h, w, tile_id):
        for i in range(h):
            for j in range(w):
                grid[r+i][c+j] = tile_id

    def remove(grid, r, c, h, w):
        for i in range(h):
            for j in range(w):
                grid[r+i][c+j] = 0

    # Find first empty cell
    def find_empty(grid):
        for i in range(H):
            for j in range(W):
                if grid[i][j] == 0:
                    return i, j
        return None, None

    def backtrack(grid, used, tile_list):
        r, c = find_empty(grid)
        if r is None:
            return True  # grid full

        for idx, (a, b) in enumerate(tile_list):
            if used[idx]:
                continue
            # Try both orientations
            for h, w in [(a, b), (b, a)]:
                if can_place(grid, r, c, h, w):
                    place(grid, r, c, h, w, idx+1)
                    used[idx] = True
                    if backtrack(grid, used, tile_list):
                        return True
                    used[idx] = False
                    remove(grid, r, c, h, w)
        return False

    used = [False]*N
    if backtrack(grid, used, tiles):
        print("Yes")
    else:
        print("No")

if __name__ == "__main__":
    solve()
```

