We need to count numbers in [start, finish] that:  

1. End with suffix `s`.  
2. Have all digits ≤ limit.  

Since `finish` can be as large as \(10^{15}\), brute force won't work.  
We can solve this by generating all possible prefixes such that the full number (prefix + s) is within range and digits are valid.  

Here’s the implementation:

```python
def numberOfPowerfulInt(start: int, finish: int, limit: int, s: str) -> int:
    def count_up_to(n: int) -> int:
        n_str = str(n)
        suffix_len = len(s)
        prefix_len = len(n_str) - suffix_len

        if prefix_len < 0:
            return 0

        # dp[i][tight] = number of ways to fill prefix from position i
        from functools import lru_cache

        @lru_cache(None)
        def dfs(pos: int, tight: bool) -> int:
            if pos == prefix_len:
                # We have placed the whole prefix, now check if suffix can fit
                # If tight is True, the suffix must be <= the last digits of n_str
                if tight:
                    suffix_part = n_str[prefix_len:]
                    return 1 if int(suffix_part) >= int(s) else 0
                return 1

            max_digit = int(n_str[pos]) if tight else limit
            total = 0
            for d in range(0, max_digit + 1):
                if d > limit:
                    break
                next_tight = tight and (d == max_digit)
                total += dfs(pos + 1, next_tight)
            return total

        return dfs(0, True)

    return count_up_to(finish) - count_up_to(start - 1)
```

