Looking at this problem, we need to find the minimum number of operations to transform x into y using the four allowed operations:
- Divide by 11 (if divisible)
- Divide by 5 (if divisible)
- Increment by 1
- Decrement by 1

This is a shortest path problem that can be solved with BFS (Breadth-First Search) since each operation has equal cost (1 operation).

```python
from collections import deque

def minOperations(x: int, y: int) -> int:
    if x == y:
        return 0

    visited = set()
    queue = deque([(x, 0)])
    visited.add(x)

    while queue:
        current, steps = queue.popleft()

        # Try all four operations
        # Decrement by 1
        if current - 1 >= 1:
            if current - 1 == y:
                return steps + 1
            if current - 1 not in visited:
                visited.add(current - 1)
                queue.append((current - 1, steps + 1))

        # Increment by 1
        if current + 1 <= 10000:
            if current + 1 == y:
                return steps + 1
            if current + 1 not in visited:
                visited.add(current + 1)
                queue.append((current + 1, steps + 1))

        # Divide by 5
        if current % 5 == 0:
            new_val = current // 5
            if new_val == y:
                return steps + 1
            if new_val not in visited:
                visited.add(new_val)
                queue.append((new_val, steps + 1))

        # Divide by 11
        if current % 11 == 0:
            new_val = current // 11
            if new_val == y:
                return steps + 1
            if new_val not in visited:
                visited.add(new_val)
                queue.append((new_val, steps + 1))

    return -1  # Should never reach here given constraints
