from typing import List
import math

class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        rx, ry = self.find(x), self.find(y)
        if rx == ry:
            return
        if self.rank[rx] < self.rank[ry]:
            self.parent[rx] = ry
        elif self.rank[rx] > self.rank[ry]:
            self.parent[ry] = rx
        else:
            self.parent[ry] = rx
            self.rank[rx] += 1

def canTraverseAllPairs(nums: List[int]) -> bool:
    n = len(nums)
    if n == 1:
        return True

    uf = UnionFind(n)

    # Map each factor to the first index where it appears
    factor_to_index = {}

    for i, num in enumerate(nums):
        temp = num
        d = 2
        while d * d <= temp:
            if temp % d == 0:
                if d in factor_to_index:
                    uf.union(i, factor_to_index[d])
                else:
                    factor_to_index[d] = i
                while temp % d == 0:
                    temp //= d
            d += 1 if d == 2 else 2  # skip even numbers after 2
        if temp > 1:
            if temp in factor_to_index:
                uf.union(i, factor_to_index[temp])
            else:
                factor_to_index[temp] = i

    root = uf.find(0)
    return all(uf.find(i) == root for i in range(1, n))
