We need to generate a valid N×N grid where:  

- Each row and column has exactly one A, one B, and one C.  
- The first character in row i is R[i].  
- The first character in column j is C[j].  
- N is small (3 to 5), so we can use brute force with backtracking.  

Here’s the implementation:  

```python
import sys
from itertools import permutations

def solve():
    input_data = sys.stdin.read().strip().split()
    N = int(input_data[0])
    R = input_data[1]
    C = input_data[2]

    # We'll try to fill row by row
    # Each row must contain exactly one A, B, C, and the rest empty
    # And the first char must match R[i]

    # Precompute all possible rows
    possible_rows = []
    base = ['.'] * N
    for a_pos in range(N):
        for b_pos in range(N):
            if a_pos == b_pos:
                continue
            for c_pos in range(N):
                if c_pos == a_pos or c_pos == b_pos:
                    continue
                row = base[:]
                row[a_pos] = 'A'
                row[b_pos] = 'B'
                row[c_pos] = 'C'
                possible_rows.append(''.join(row))

    # Filter by first char matching R[i]
    row_options = []
    for i in range(N):
        opts = [r for r in possible_rows if r[0] == R[i]]
        row_options.append(opts)

    # Check column constraints: each column must have exactly one A, B, C
    # And topmost char in col j must be C[j]

    def backtrack(grid, col_counts, col_first_set):
        if len(grid) == N:
            # Check column first characters
            for j in range(N):
                if col_first_set[j] != C[j]:
                    return False
            # Check counts
            for j in range(N):
                if col_counts['A'][j] != 1 or col_counts['B'][j] != 1 or col_counts['C'][j] != 1:
                    return False
            return True

        i = len(grid)
        for row_str in row_options[i]:
            # Check if this row can fit
            new_counts = {
                'A': col_counts['A'][:],
                'B': col_counts['B'][:],
                'C': col_counts['C'][:]
            }
            new_first_set = col_first_set[:]
            ok = True
            for j, ch in enumerate(row_str):
                if ch != '.':
                    if new_counts[ch][j] >= 1:
                        ok = False
                        break
                    new_counts[ch][j] += 1
                    if new_first_set[j] == '':
                        new_first_set[j] = ch
            if not ok:
                continue

            grid.append(row_str)
            if backtrack(grid, new_counts, new_first_set):
                return True
            grid.pop()
        return False

    init_counts = {'A': [0]*N, 'B': [0]*N, 'C': [0]*N}
    init_first = [''] * N

    result_grid = []
    if backtrack(result_grid, init_counts, init_first):
        print("Yes")
        for row in result_grid:
            print(row)
    else:
        print("No")

if __name__ == "__main__":
    solve()
```

