def maximumSubarraySum(nums, k):
    prefix_sum = 0
    best = float('-inf')
    earliest_prefix = {}

    for i, num in enumerate(nums):
        prefix_sum += num

        if num - k in earliest_prefix:
            best = max(best, prefix_sum - earliest_prefix[num - k])
        if num + k in earliest_prefix:
            best = max(best, prefix_sum - earliest_prefix[num + k])

        if num not in earliest_prefix or prefix_sum - num < earliest_prefix[num]:
            earliest_prefix[num] = prefix_sum - num

    return best if best != float('-inf') else 0
